{
  "summary": "This paper proposes a novel, scalable approach to approximating human similarity judgments using language-based methods, including a new adaptive tagging pipeline (STEP-Tag) and large language model embeddings, evaluated across images, audio, and video modalities. The authors demonstrate that language-based and hybrid stacked methods outperform traditional DNN-based approaches, offering a modality-agnostic and efficient alternative to costly pairwise human judgments.",
  "strengths": [
    {
      "point": "Comprehensive large-scale evaluation across multiple modalities",
      "evidence": "Evaluation of 611 pre-trained models spanning images, audio, and video, with new human similarity and textual data collected for these modalities."
    },
    {
      "point": "Introduction of STEP-Tag, an adaptive iterative tagging pipeline",
      "evidence": "STEP-Tag improves tag quality and diversity through iterative creation and validation, outperforming single-pass or random tag baselines."
    },
    {
      "point": "Demonstration that language-based similarity approximations outperform DNN-only methods",
      "evidence": "Language-based methods using LLM embeddings consistently yield better alignment with human similarity judgments than 611 evaluated DNN embeddings."
    },
    {
      "point": "Hybrid stacked embeddings combining DNN and LLM features achieve best performance",
      "evidence": "Stacked methods with rescaled LLM embeddings outperform both language-only and DNN-only approaches across all modalities."
    },
    {
      "point": "Provision of extensive resources for replication and future research",
      "evidence": "Release of a large behavioral dataset with 206,339 human judgments, textual data, modeling code, and a practical guide for similarity approximation."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior work on language-based similarity approximation",
      "evidence": "The paper lacks thorough discussion or empirical comparison with existing zero-shot learning or multimodal retrieval methods that use textual descriptions."
    },
    {
      "point": "Lack of justification and sensitivity analysis for STEP-Tag iteration parameters",
      "evidence": "No rationale or ablation studies on iteration counts, participant numbers, or stopping criteria in the iterative tagging pipeline."
    },
    {
      "point": "No ablation separating effects of tag quality versus quantity on similarity performance",
      "evidence": "The impact of collecting more low-quality tags versus fewer high-quality tags is not explored."
    },
    {
      "point": "Potential under-optimization of DNN baselines",
      "evidence": "Unclear if DNN embeddings were fine-tuned or adapted to the similarity task, possibly underestimating their performance."
    },
    {
      "point": "Evaluation metrics focus mainly on correlation without detailed error analysis",
      "evidence": "No additional metrics such as mean squared error or qualitative error analysis to understand systematic biases or error types."
    },
    {
      "point": "Limited generalization tests beyond images, audio, and video",
      "evidence": "No evaluation on text-only datasets, medical images, or low-resource languages despite these being motivating challenges."
    },
    {
      "point": "Reproducibility concerns due to missing details on human judgment protocols and hyperparameter tuning",
      "evidence": "Lack of detailed participant instructions, quality control, inter-rater reliability, and tuning procedures for stacked embedding hyperparameters."
    },
    {
      "point": "Ambiguity in the definition of 'similarity' across modalities",
      "evidence": "No clear specification of the notion of similarity participants were asked to judge, complicating interpretation."
    },
    {
      "point": "Potential biases in crowdsourced textual data not addressed",
      "evidence": "No discussion of demographic, cultural, or language proficiency biases affecting captions and tags."
    },
    {
      "point": "Scalability of STEP-Tag to very large datasets not empirically demonstrated",
      "evidence": "No evidence or discussion on handling datasets with millions of stimuli where even O(N) human annotations may be costly."
    },
    {
      "point": "No analysis of how choice of language model affects performance",
      "evidence": "Different LLM architectures, sizes, or training corpora impacts on similarity approximation quality are not studied."
    },
    {
      "point": "Simple concatenation for embedding fusion may be suboptimal",
      "evidence": "More sophisticated fusion methods like learned weighted combinations or attention mechanisms are not explored."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed language-based similarity approximation compare empirically to existing zero-shot or multimodal retrieval methods that also use textual descriptions?",
      "motivation": "Clarifying novelty and incremental contribution requires benchmarking against related prior work."
    },
    {
      "question": "What is the sensitivity of STEP-Tag performance to iteration parameters and participant numbers, and can the pipeline scale efficiently to datasets with millions of stimuli?",
      "motivation": "Understanding robustness and scalability is critical for practical deployment in large-scale settings."
    },
    {
      "question": "How do different definitions or instructions of 'similarity' affect human judgments and the resulting approximation performance across modalities?",
      "motivation": "Ambiguity in similarity notions may limit interpretability and generalizability of results."
    },
    {
      "question": "Would fine-tuning or adapting DNN embeddings to the similarity task improve their performance relative to language-based methods?",
      "motivation": "Ensuring fair baseline comparisons is necessary to validate claims about method superiority."
    },
    {
      "question": "How does the choice of language model architecture and size impact the quality of similarity approximations?",
      "motivation": "Understanding robustness and limitations of LLM-based embeddings informs applicability to different domains."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
